#include <bits/stdc++.h>
using namespace std;
const int N=5e4+10;
int n,q,h[N],st[N][17][2];
int main(){
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++)
        scanf("%d",&h[i]);
    for(int i=n;i;i--){
        st[i][0][0]=st[i][0][1]=h[i];
        for(int j=1;i+(1<<j)-1<=n;j++){
            st[i][j][0]=min(st[i][j-1][0],st[i+(1<<j-1)][j-1][0]);
            st[i][j][1]=max(st[i][j-1][1],st[i+(1<<j-1)][j-1][1]);
        }
    }
    while(q--){
        int a,b,len;
        scanf("%d%d",&a,&b);
        len=log2(b-a+1);
        printf("%d\n",max(st[a][len][1],st[b-(1<<len)+1][len][1])-min(st[a][len][0],st[b-(1<<len)+1][len][0]));
    }
    return 0;
}
